import useCanvasObjects from '../hooks/useCanvasObjects'
import Sidebar from './Sidebar'

function Main() {
    const {
            canvasRef,
        objects,
        newObject,
        startDragging,
        dragging,
        stopDragging,
        } = useCanvasObjects();

    return (
        <div className="main">
            <Sidebar></Sidebar>

            <div
                className="canvas-container"
                ref={canvasRef}
                onMouseMove={dragging}
                onMouseUp={stopDragging}
                style={{ position: 'relative' }}
            >
                {objects.map((obj) => (
                    <div
                        key={obj.id}
                        className="obj"
                        onMouseDown={(e) => startDragging(obj.id, e)}
                        style={{
                            position: 'absolute',
                            left: obj.left,
                            top: obj.top,
                        }}
                    />
                ))}
            </div>
        </div>
    )
}

export default Main;
